pub fn mailbox_icon(role: Option<&str>) -> &'static str {
    match role {
        Some("inbox") => ICON_INBOX,
        Some("drafts") => ICON_FILE_EDIT,
        Some("sent") => ICON_SEND,
        Some("archive") => ICON_ARCHIVE,
        Some("junk") => ICON_ALERT_TRIANGLE,
        Some("trash") => ICON_TRASH,
        _ => ICON_FOLDER,
    }
}
